  'shape_request':  {'nl': 'Vorm aanvragen (laten intekenen)', 'en': 'Request shape (ask to be drawn)', 'de': 'Form anfragen (einzeichnen lassen)', 'fr': 'Demander le tracé', 'es': 'Solicitar forma (que la dibujen)', 'pl': 'Poproś o narysowanie kształtu'},
  'shape_requested_ok': {'nl': 'Bedankt! Een moderator gaat dit water intekenen.', 'en': 'Thanks! A moderator will draw this water.', 'de': 'Danke! Ein Moderator zeichnet dieses Gewässer ein.', 'fr': 'Merci ! Un modérateur va tracer cette eau.', 'es': '¡Gracias! Un moderador dibujará este agua.', 'pl': 'Dzięki! Moderator narysuje ten akwen.'},
  'shape_requested_badge': {'nl': 'aangevraagd', 'en': 'requested', 'de': 'angefragt', 'fr': 'demandé', 'es': 'solicitado', 'pl': 'zgłoszone'},
  'center_hint':    {'nl': 'hier plaatsen', 'en': 'place here', 'de': 'hier setzen', 'fr': 'placer ici', 'es': 'colocar aquí', 'pl': 'umieść tu'},
  'water_is_paid':  {'nl': 'Betaalwater (forelvijver e.d.)', 'en': 'Paid water (trout pond etc.)', 'de': 'Bezahlgewässer (Forellenteich usw.)', 'fr': 'Eau payante (étang à truites, etc.)', 'es': 'Agua de pago (estanque de truchas, etc.)', 'pl': 'Łowisko płatne (np. pstrągowe)'},
  'water_booking_url': {'nl': 'Boekings-/website-link', 'en': 'Booking / website link', 'de': 'Buchungs-/Website-Link', 'fr': 'Lien de réservation/site', 'es': 'Enlace de reserva/web', 'pl': 'Link rezerwacji/strony'},
  'place_water_hint': {'nl': 'Schuif de kaart zodat het kruis op het water staat.', 'en': 'Move the map so the marker is on the water.', 'de': 'Verschiebe die Karte, bis das Kreuz auf dem Wasser liegt.', 'fr': 'Déplace la carte pour mettre le repère sur l\'eau.', 'es': 'Mueve el mapa para que la marca quede sobre el agua.', 'pl': 'Przesuń mapę tak, by znacznik był na wodzie.'},
  'place_spot_hint': {'nl': 'Schuif de kaart naar de plek van je stek.', 'en': 'Move the map to your spot\'s location.', 'de': 'Verschiebe die Karte zur Stelle deines Spots.', 'fr': 'Déplace la carte vers l\'emplacement de ton spot.', 'es': 'Mueve el mapa hasta la ubicación de tu punto.', 'pl': 'Przesuń mapę do miejsca swojego stanowiska.'},
  'place_confirm':  {'nl': 'Bevestig', 'en': 'Confirm', 'de': 'Bestätigen', 'fr': 'Confirmer', 'es': 'Confirmar', 'pl': 'Potwierdź'},
  'place_gps':      {'nl': 'Mijn GPS', 'en': 'My GPS', 'de': 'Mein GPS', 'fr': 'Mon GPS', 'es': 'Mi GPS', 'pl': 'Mój GPS'},
  'shape_help':     {'nl': 'Uitleg', 'en': 'Help', 'de': 'Hilfe', 'fr': 'Aide', 'es': 'Ayuda', 'pl': 'Pomoc'},
  'shape_help_title': {'nl': 'Water intekenen', 'en': 'Drawing a water', 'de': 'Gewässer einzeichnen', 'fr': 'Tracer une eau', 'es': 'Dibujar un agua', 'pl': 'Rysowanie akwenu'},
  'shape_help_body': {
    'nl': '1. Tik eerst op "Uit OSM ophalen" - meestal staat de vorm er al en ben je klaar.\n2. Niet gevonden of klopt niet? Tik met de pen langs de oever, punt voor punt, de hele waterkant rond.\n3. Zet in bochten meer punten, op rechte stukken minder.\n4. Punt fout? Tik erop om te wissen, of "Wis laatste".\n5. "Opslaan" (min. 3 punten). De vorm bepaalt waar inchecken en stekken mogen - dus teken zo nauwkeurig mogelijk.',
    'en': '1. First tap "Fetch from OSM" - usually the shape is already there and you\'re done.\n2. Not found or wrong? Tap along the shore with the pen, point by point, all the way around.\n3. More points in bends, fewer on straight stretches.\n4. Wrong point? Tap it to remove, or "Undo last".\n5. "Save" (min. 3 points). The shape decides where check-in and spots are allowed - so draw as precisely as possible.',
    'de': '1. Zuerst "Aus OSM holen" - meist ist die Form schon da.\n2. Nicht gefunden/falsch? Mit dem Stift Punkt für Punkt am Ufer entlang, einmal rundherum.\n3. In Kurven mehr Punkte, auf geraden Stücken weniger.\n4. Falscher Punkt? Antippen zum Löschen, oder "Letzten löschen".\n5. "Speichern" (min. 3 Punkte). Die Form bestimmt Check-in und Stellen - also so genau wie möglich zeichnen.',
    'fr': '1. D\'abord "Récupérer d\'OSM" - souvent la forme y est déjà.\n2. Absente/fausse ? Touche au stylet le long de la rive, point par point, tout le tour.\n3. Plus de points dans les virages, moins sur les lignes droites.\n4. Mauvais point ? Touche-le pour l\'enlever, ou "Annuler dernier".\n5. "Enregistrer" (min. 3 points). La forme décide du check-in et des spots - trace donc le plus précisément possible.',
    'es': '1. Primero "Obtener de OSM" - normalmente la forma ya está.\n2. ¿No está o está mal? Toca con el lápiz a lo largo de la orilla, punto a punto, toda la vuelta.\n3. Más puntos en las curvas, menos en los tramos rectos.\n4. ¿Punto mal? Tócalo para borrarlo, o "Deshacer último".\n5. "Guardar" (mín. 3 puntos). La forma decide el check-in y los puntos - dibuja con la mayor precisión.',
    'pl': '1. Najpierw "Pobierz z OSM" - zwykle kształt już tam jest.\n2. Brak/źle? Stuknij piórem wzdłuż brzegu, punkt po punkcie, dookoła.\n3. Więcej punktów na zakrętach, mniej na prostych.\n4. Zły punkt? Stuknij, aby usunąć, lub "Cofnij ostatni".\n5. "Zapisz" (min. 3 punkty). Kształt decyduje o meldowaniu i stanowiskach - rysuj jak najdokładniej.',
  },
};

String _mLoc(BuildContext c) => Provider.of<I18n>(c, listen: false).locale;
String mui(BuildContext c, String key) { final m = kMapUi[key]; return m?[_mLoc(c)] ?? m?['en'] ?? key; }
String busyLevelLabel(BuildContext c, String level) => mui(c, 'busy_$level');

/// Per-land vergunning-uitleg (6-talig), identiek aan web map-countries.ts.
/// Getoond bij een grijs water zodat elke visser ziet hoe het in zijn land werkt.
const Map<String, Map<String, String>> kCountryLicence = {
  "Netherlands": {'nl': "In Nederland vis je met de VISpas van Sportvisserij Nederland. Op wateren in de Landelijke Lijst mag elke VISpas-houder vissen; verenigingswater vereist lidmaatschap van die HSV. Friesland heeft een eigen Fiskfergunning.", 'en': "In the Netherlands you fish with the VISpas from Sportvisserij Nederland. Any VISpas holder may fish waters on the National List; club waters require membership of that club. Friesland has its own Fiskfergunning.", 'de': "In den Niederlanden angelt man mit dem VISpas von Sportvisserij Nederland. Gewässer der Landesliste darf jeder VISpas-Inhaber befischen; Vereinsgewässer erfordern die Mitgliedschaft. Friesland hat eine eigene Fiskfergunning.", 'fr': "Aux Pays-Bas on pêche avec le VISpas de Sportvisserij Nederland. Tout titulaire du VISpas peut pêcher les eaux de la Liste nationale ; les eaux de club exigent l'adhésion. La Frise a sa propre Fiskfergunning.", 'es': "En los Países Bajos se pesca con el VISpas de Sportvisserij Nederland. Cualquier titular del VISpas puede pescar en las aguas de la Lista Nacional; las aguas de club requieren afiliación. Frisia tiene su propia Fiskfergunning.", 'pl': "W Holandii łowi się z VISpas od Sportvisserij Nederland. Wody z Listy Krajowej może łowić każdy posiadacz VISpas; wody klubowe wymagają członkostwa. Fryzja ma własny Fiskfergunning."},
  "Belgium": {'nl': "In België regel je het visverlof per gewest: Vlaanderen (visverlof via Natuur & Bos) dekt het openbare water; in Wallonië heb je een permis de pêche nodig, op onbevaarbaar water plus een kaart van de société de pêche. Brussel heeft een eigen vergunning (catch & release).", 'en': "In Belgium the permit is regional: Flanders (visverlof) covers public water; Wallonia needs a permis de pêche, plus a société de pêche card on non-navigable waters. Brussels has its own catch-and-release permit.", 'de': "In Belgien ist die Erlaubnis regional: Flandern (visverlof) deckt das öffentliche Wasser; Wallonien braucht einen permis de pêche, an nicht schiffbaren Gewässern zusätzlich eine Karte der société de pêche. Brüssel hat eine eigene Catch-&-Release-Erlaubnis.", 'fr': "En Belgique le permis est régional : la Flandre (visverlof) couvre l'eau publique ; la Wallonie exige un permis de pêche, plus une carte de société de pêche sur les eaux non navigables. Bruxelles a son propre permis (no-kill).", 'es': "En Bélgica el permiso es regional: Flandes (visverlof) cubre el agua pública; Valonia exige un permis de pêche, y en aguas no navegables una tarjeta de société de pêche. Bruselas tiene su propio permiso (captura y suelta).", 'pl': "W Belgii pozwolenie jest regionalne: Flandria (visverlof) obejmuje wody publiczne; Walonia wymaga permis de pêche, a na wodach nieżeglownych dodatkowo karty société de pêche. Bruksela ma własne pozwolenie (no-kill)."},
  "Luxembourg": {'nl': "In Luxemburg heb je een nationale visvergunning (licence de pêche) nodig, aangevuld met een lokale toelating per water.", 'en': "Luxembourg requires a national fishing licence plus a local permit per water.", 'de': "Luxemburg erfordert einen nationalen Fischereischein plus eine örtliche Erlaubnis je Gewässer.", 'fr': "Le Luxembourg exige une licence de pêche nationale et une autorisation locale par eau.", 'es': "Luxemburgo requiere una licencia nacional más un permiso local por agua.", 'pl': "Luksemburg wymaga krajowej licencji oraz lokalnego pozwolenia na daną wodę."},
  "Germany": {'nl': "In Duitsland heb je een Fischereischein (visdiploma via een examen, per deelstaat) nodig én per water een Erlaubnisschein van de vereniging die dat water pacht (dag- of jaarkaart). Bijna elk water is verpacht. Sommige deelstaten (o.a. Mecklenburg-Vorpommern) kennen een toeristenvergunning zonder examen.", 'en': "In Germany you need a Fischereischein (licence obtained by exam, per federal state) plus an Erlaubnisschein per water from the club that leases it (day or annual ticket). Almost every water is leased. Some states (e.g. Mecklenburg-Vorpommern) offer a tourist permit without an exam.", 'de': "In Deutschland brauchst du einen Fischereischein (Prüfung, je Bundesland) und je Gewässer einen Erlaubnisschein des pachtenden Vereins (Tages- oder Jahreskarte). Fast jedes Gewässer ist verpachtet. Einige Bundesländer (z. B. Mecklenburg-Vorpommern) bieten einen Touristenfischereischein ohne Prüfung.", 'fr': "En Allemagne il faut un Fischereischein (permis par examen, selon le Land) et, par eau, un Erlaubnisschein de l'association qui la loue (carte jour ou année). Presque toutes les eaux sont louées. Certains Länder (p. ex. Mecklembourg-Poméranie) proposent un permis touristique sans examen.", 'es': "En Alemania necesitas un Fischereischein (licencia por examen, según el estado) y, por agua, un Erlaubnisschein del club que la arrienda (entrada diaria o anual). Casi todas las aguas están arrendadas. Algunos estados (p. ej. Mecklemburgo-Pomerania) ofrecen un permiso turístico sin examen.", 'pl': "W Niemczech potrzebujesz Fischereischein (karta zdawana na egzaminie, zależnie od landu) oraz Erlaubnisschein na daną wodę od dzierżawiącego ją klubu (bilet dzienny lub roczny). Prawie każda woda jest wydzierżawiona. Niektóre landy (np. Meklemburgia-Pomorze Przednie) oferują pozwolenie turystyczne bez egzaminu."},
  "Austria": {'nl': "In Oostenrijk heb je een Fischerkarte (deelstaat) én een Lizenz per water nodig. Veel water is in beheer van verenigingen of privé.", 'en': "In Austria you need a Fischerkarte (per state) plus a licence per water. Much water is club-managed or private.", 'de': "In Österreich brauchst du eine Fischerkarte (Bundesland) und eine Lizenz je Gewässer. Vieles ist Vereins- oder Privatgewässer.", 'fr': "En Autriche il faut une Fischerkarte (par Land) et une licence par eau. Beaucoup d'eaux sont gérées par des clubs ou privées.", 'es': "En Austria necesitas una Fischerkarte (por estado) y una licencia por agua. Muchas aguas son de club o privadas.", 'pl': "W Austrii potrzebna jest Fischerkarte (land) i licencja na daną wodę. Wiele wód jest klubowych lub prywatnych."},
  "Switzerland": {'nl': "In Zwitserland regel je een patent/vergunning per kanton. Sommige wateren zijn verpacht aan verenigingen (Revier).", 'en': "In Switzerland you get a patent/permit per canton. Some waters are leased to clubs (Revier).", 'de': "In der Schweiz löst du ein Patent/Bewilligung je Kanton. Manche Gewässer sind an Vereine verpachtet (Revier).", 'fr': "En Suisse on prend une patente par canton. Certaines eaux sont louées à des clubs (Revier).", 'es': "En Suiza se obtiene una patente por cantón. Algunas aguas están arrendadas a clubes (Revier).", 'pl': "W Szwajcarii wykupuje się patent na kanton. Niektóre wody są dzierżawione przez kluby (Revier)."},
  "France": {'nl': "In Frankrijk vis je met een carte de pêche van een lokale vereniging (AAPPMA), online op cartedepeche.fr. Dankzij de wederkerigheid (EHGO/CHI/URNE) is één jaarkaart geldig in ~91 departementen. Privéwater, niet-wederkerige trajecten en visreservaten vallen daarbuiten.", 'en': "In France you fish with a carte de pêche from a local association (AAPPMA), online at cartedepeche.fr. Thanks to reciprocity (EHGO/CHI/URNE) one annual card is valid in ~91 departments. Private waters, non-reciprocal stretches and fishing reserves are excluded.", 'de': "In Frankreich angelt man mit einer carte de pêche eines örtlichen Vereins (AAPPMA), online auf cartedepeche.fr. Dank Gegenseitigkeit (EHGO/CHI/URNE) gilt eine Jahreskarte in ~91 Departements. Privatgewässer, nicht-reziproke Abschnitte und Schongebiete sind ausgenommen.", 'fr': "En France on pêche avec une carte de pêche d'une AAPPMA locale, en ligne sur cartedepeche.fr. Grâce à la réciprocité (EHGO/CHI/URNE), une carte annuelle est valable dans ~91 départements. Les eaux privées, parcours non réciprocitaires et réserves en sont exclus.", 'es': "En Francia se pesca con una carte de pêche de una AAPPMA local, en cartedepeche.fr. Gracias a la reciprocidad (EHGO/CHI/URNE) una tarjeta anual vale en ~91 departamentos. Aguas privadas, tramos no recíprocos y reservas quedan fuera.", 'pl': "We Francji łowi się na carte de pêche lokalnego stowarzyszenia (AAPPMA), online na cartedepeche.fr. Dzięki wzajemności (EHGO/CHI/URNE) roczna karta jest ważna w ~91 departamentach. Wody prywatne, odcinki bez wzajemności i rezerwaty są wyłączone."},
  "United Kingdom": {'nl': "In het VK heb je vrijwel overal toestemming van de waterbeheerder nodig (day ticket of clublidmaatschap). In Engeland & Wales heb je dáárnaast een landelijke rod licence nodig (Environment Agency). In Schotland is er geen rod licence, maar wel altijd een permit van de eigenaar/beat.", 'en': "In the UK you almost always need permission from the water's manager (day ticket or club membership). In England & Wales you also need a national rod licence (Environment Agency). Scotland has no rod licence but always needs a permit from the owner/beat.", 'de': "Im UK brauchst du fast überall die Erlaubnis des Gewässerbewirtschafters (Tageskarte oder Vereinsmitgliedschaft). In England & Wales zusätzlich eine landesweite rod licence (Environment Agency). Schottland hat keine rod licence, aber immer ein Permit des Eigentümers/Beats.", 'fr': "Au Royaume-Uni il faut presque toujours l'autorisation du gestionnaire (ticket jour ou adhésion club). En Angleterre & Pays de Galles, en plus une rod licence nationale (Environment Agency). L'Écosse n'a pas de rod licence mais exige toujours un permis du propriétaire/beat.", 'es': "En el Reino Unido casi siempre necesitas permiso del gestor del agua (entrada de día o socio del club). En Inglaterra y Gales además una rod licence nacional (Environment Agency). Escocia no tiene rod licence pero siempre exige un permiso del propietario/beat.", 'pl': "W Wielkiej Brytanii prawie zawsze potrzebujesz zgody zarządcy wody (dniówka lub członkostwo klubu). W Anglii i Walii dodatkowo krajowa rod licence (Environment Agency). Szkocja nie ma rod licence, ale zawsze wymaga zezwolenia właściciela/beatu."},
  "Ireland": {'nl': "In Ierland is vissen op witvis en snoek vaak vrij; voor zalm en zeeforel heb je een State licence nodig. Meestal heb je dáárnaast een permit van de waterbeheerder (club of privé) nodig.", 'en': "In Ireland coarse and pike fishing is often free; salmon and sea trout require a State licence. You usually also need a permit from the water's manager (club or private).", 'de': "In Irland ist Angeln auf Weißfisch und Hecht oft frei; für Lachs und Meerforelle ist eine State Licence nötig. Meist brauchst du zusätzlich ein Permit des Bewirtschafters (Verein oder privat).", 'fr': "En Irlande la pêche du coarse et du brochet est souvent libre ; saumon et truite de mer exigent une licence d'État. Il faut généralement aussi un permis du gestionnaire (club ou privé).", 'es': "En Irlanda la pesca de coarse y lucio suele ser libre; salmón y trucha de mar requieren licencia estatal. Normalmente también necesitas un permiso del gestor (club o privado).", 'pl': "W Irlandii łowienie białej ryby i szczupaka bywa wolne; łosoś i troć wymagają licencji państwowej. Zwykle potrzebujesz też zezwolenia zarządcy (klub lub prywatny)."},
  "Spain": {'nl': "In Spanje regelt elke regio (comunidad autónoma) de visserij; je hebt altijd een regionale licencia nodig. In vrije wateren (aguas libres) volstaat die; bij een coto heb je een aparte dagvergunning per traject nodig, vaak via reservering of loting.", 'en': "In Spain each region (comunidad autónoma) manages fishing; you always need a regional licencia. In free waters (aguas libres) that is enough; at a coto you need a separate per-stretch day permit, often by booking or lottery.", 'de': "In Spanien regelt jede Region (Comunidad Autónoma) das Angeln; du brauchst immer eine regionale Licencia. In freien Gewässern (aguas libres) genügt sie; an einem Coto brauchst du zusätzlich eine Tageserlaubnis je Abschnitt, oft per Reservierung oder Verlosung.", 'fr': "En Espagne chaque région (comunidad autónoma) gère la pêche ; il faut toujours une licencia régionale. En eaux libres (aguas libres) elle suffit ; sur un coto, un permis journalier par tronçon est requis, souvent par réservation ou tirage.", 'es': "En España cada comunidad autónoma regula la pesca; siempre necesitas una licencia autonómica. En aguas libres basta; en un coto necesitas un permiso por tramo y día, a menudo por reserva o sorteo.", 'pl': "W Hiszpanii każdy region (comunidad autónoma) reguluje wędkarstwo; zawsze potrzebna jest regionalna licencia. Na wodach wolnych (aguas libres) wystarcza; na coto trzeba dodatkowo dzienne zezwolenie na odcinek, często przez rezerwację lub losowanie."},
  "Poland": {'nl': "In Polen heb je vanaf 14 jaar een karta wędkarska (visdiploma) nodig plus een zezwolenie van de beheerder. De meeste wateren zijn van de PZW: je betaalt lidmaatschap én een district-bijdrage (okręg). Commerciële vijvers (płać i łów) vergen geen diploma — je koopt een dagkaart.", 'en': "In Poland, from age 14 you need a karta wędkarska (angling card) plus a permit from the manager. Most waters belong to the PZW: you pay membership and a district (okręg) fee. Commercial ponds (pay-and-fish) need no card — you buy a day ticket.", 'de': "In Polen brauchst du ab 14 Jahren eine karta wędkarska (Angelkarte) plus eine Erlaubnis des Bewirtschafters. Die meisten Gewässer gehören dem PZW: du zahlst Mitgliedschaft und einen Bezirksbeitrag (okręg). Kommerzielle Teiche (pay & fish) brauchen keine Karte — Tageskarte kaufen.", 'fr': "En Pologne, dès 14 ans, il faut une karta wędkarska et une autorisation du gestionnaire. La plupart des eaux appartiennent au PZW : adhésion + cotisation de district (okręg). Les étangs commerciaux (payer et pêcher) ne demandent pas de carte — un ticket jour suffit.", 'es': "En Polonia, desde los 14 años necesitas una karta wędkarska y un permiso del gestor. La mayoría de las aguas son del PZW: pagas afiliación y una cuota de distrito (okręg). Los estanques comerciales (pagar y pescar) no requieren carné — compras entrada diaria.", 'pl': "W Polsce od 14. roku życia potrzebna jest karta wędkarska oraz zezwolenie gospodarza. Większość wód należy do PZW: opłacasz składkę członkowską i okręgową. Łowiska komercyjne (płać i łów) nie wymagają karty — kupujesz zezwolenie jednorazowe."},
};

/// Uitleg voor het land van dit water in de huidige app-taal (leeg = onbekend land).
String mapCountryLicence(BuildContext c, String? country) {
  if (country == null) return '';
  final m = kCountryLicence[country];
  if (m == null) return '';
  return m[_mLoc(c)] ?? m['en'] ?? '';
}
